package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mockStatic;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class JavaVersionTest {

  private static MockedStatic<System> systemMock;

  @BeforeAll
  static void setUp() {
    systemMock = mockStatic(System.class);
  }

  @AfterAll
  static void tearDown() {
    systemMock.close();
  }

  @Test
  void testDetermineMajorJavaVersion_java8() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("1.8.0_251");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);

    assertEquals(8, majorVersion);
  }

  @Test
  void testDetermineMajorJavaVersion_java11() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("11.0.7");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);

    assertEquals(11, majorVersion);
  }

  @Test
  void testDetermineMajorJavaVersion_java9() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("9");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);

    assertEquals(9, majorVersion);
  }

  @Test
  void testDetermineMajorJavaVersion_java13_0_1() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("13.0.1");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);

    assertEquals(13, majorVersion);
  }

  @Test
  void testDetermineMajorJavaVersion_unusualFormat() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("17-ea");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);

    assertEquals(17, majorVersion);
  }
}
